// src/App.js

import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import MyGroups from './pages/MyGroups';
import CreateGroup from './pages/CreateGroup'; // Ajouter la page de création de groupe
import Login from './pages/Login';

function App() {
    const currentUser = {
        username: 'alice', // Exemple d'utilisateur connecté
    };

    return (
        <Router>
            <Navbar />

            <Routes>
                <Route path="/" element={<Login />} />
                <Route path="/my-groups" element={<MyGroups currentUser={currentUser} />} />
                <Route path="/create-group" element={<CreateGroup currentUser={currentUser} />} />
            </Routes>
        </Router>
    );
}

export default App;
